SELECT DISTINCT q.id, q.question_code, q.status, q.created_by, q.created_time, q.updated_by, q.updated_time, q.delete_flag FROM questionnaire_question q LEFT JOIN questionnaire_question_text qt ON q.id = qt.question_id AND qt.delete_flag = 0 WHERE q.delete_flag = 0
AND q.question_code LIKE CONCAT('%', #{questionCode}, '%')
AND qt.question_text LIKE CONCAT('%', #{questionText}, '%')
AND qt.language = #{language}
AND q.created_by LIKE CONCAT('%', #{createdBy}, '%')
AND TO_CHAR(q.created_time, 'YYYY-MM-DD') = #{createdDate}
AND q.updated_by LIKE CONCAT('%', #{updatedBy}, '%')
AND TO_CHAR(q.updated_time, 'YYYY-MM-DD') = #{updatedDate}
ORDER BY q.created_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT q.id) FROM questionnaire_question q LEFT JOIN questionnaire_question_text qt ON q.id = qt.question_id AND qt.delete_flag = 0 WHERE q.delete_flag = 0
AND q.question_code LIKE CONCAT('%', #{questionCode}, '%')
AND qt.question_text LIKE CONCAT('%', #{questionText}, '%')
AND qt.language = #{language}
AND q.created_by LIKE CONCAT('%', #{createdBy}, '%')
AND TO_CHAR(q.created_time, 'YYYY-MM-DD') = #{createdDate}
AND q.updated_by LIKE CONCAT('%', #{updatedBy}, '%')
AND TO_CHAR(q.updated_time, 'YYYY-MM-DD') = #{updatedDate}
